const LangCtx = createContext({ lang: "en", setLang: () => {}, t: (_, en) => en, rtl: false });

export const LangProvider = ({ children }) => {
  const [lang, setLang] = useState(() => {
    try { return localStorage.getItem("ui_lang") || "en"; } catch { return "en"; }
  });
  const rtl = lang === "ur";

  useEffect(() => {
    try { localStorage.setItem("ui_lang", lang); } catch { /* storage disabled */ }
    // dir/lang belong on <html>: they drive logical CSS properties, text
    // selection, and how a screen reader announces the page.
    document.documentElement.dir = rtl ? "rtl" : "ltr";
    document.documentElement.lang = lang;
    document.documentElement.classList.toggle("urdu", rtl);
  }, [lang, rtl]);

  // t(key, englishFallback) — English is the fallback, never a blank.
  const t = (key, en) => (rtl && STRINGS[key]) || en;

  return <LangCtx.Provider value={{ lang, setLang, t, rtl }}>{children}</LangCtx.Provider>;
};

export const useLang = () => useContext(LangCtx);
export default LangProvider;
